class Admin_Model_Stock extends Admin_Model_Base_Stock
{

    public static function getStockIDByCode(string $warehouseCode, bool $createIfNotExists = false) {
        if(!$warehouseCode) {
            return null;
        }
        $stock = Doctrine_Query::create()
            ->from('Admin_Model_Stock s')
            ->where('s.Code = ?', $warehouseCode)
            ->fetchOne();
        if(!$stock && $createIfNotExists) {
            $stock = new self();
            $stock->Code = $warehouseCode;
            $stock->Name = $warehouseCode;
            $stock->save();
        }
        return $stock ? $stock->ID : null;
    }

    public static function getStockByStockCode(string $warehouseCode,  bool $createIfNotExists = false): self|bool {
        $stock = Doctrine_Query::create()
            ->from('Admin_Model_Stock s')
            ->where('s.Code = ?', $warehouseCode)
            ->fetchOne();
        if(!$stock && $createIfNotExists) {
            $stock = new self();
            $stock->Code = $warehouseCode;
            $stock->Name = $warehouseCode;
            $stock->save();
        }
        return $stock ?: false;
    }
}